import {
  Transaction,
  CategoryGroup,
  DuplicateGroup,
  RunningBalanceEntry,
  SpenderSummary,
  PipelineResult,
} from "./types.js";

/**
 * Groups transactions by category and calculates totals.
 *
 * Optimized: uses a Map for O(1) category lookup and increments the running
 * total directly instead of re-reducing on every insert.
 */
export function groupByCategory(transactions: Transaction[]): CategoryGroup[] {
  const map = new Map<string, CategoryGroup>();

  for (const transaction of transactions) {
    const existing = map.get(transaction.category);
    if (existing) {
      existing.transactions.push(transaction);
      existing.total += transaction.amount;
    } else {
      const group: CategoryGroup = {
        category: transaction.category,
        transactions: [transaction],
        total: transaction.amount,
      };
      map.set(transaction.category, group);
    }
  }

  return Array.from(map.values());
}

/**
 * Finds duplicate transactions (same userId + amount + date).
 *
 * Optimized: single O(n) pass grouping transactions by composite key into a
 * Map, then emits only the groups that contain more than one transaction.
 */
export function findDuplicates(transactions: Transaction[]): DuplicateGroup[] {
  const map = new Map<string, Transaction[]>();

  for (const t of transactions) {
    const key = `${t.userId}|${t.amount}|${t.date}`;
    const bucket = map.get(key);
    if (bucket) {
      bucket.push(t);
    } else {
      map.set(key, [t]);
    }
  }

  const duplicateGroups: DuplicateGroup[] = [];
  for (const [key, group] of map) {
    if (group.length > 1) {
      duplicateGroups.push({ key, transactions: group });
    }
  }

  return duplicateGroups;
}

/**
 * Calculates running balance for a specific user, sorted by date.
 *
 * Optimized: single pass to collect user transactions, sort once, then a
 * single accumulation pass — no redundant re-scans or re-sorts.
 */
export function calculateRunningBalance(
  transactions: Transaction[],
  userId: string
): RunningBalanceEntry[] {
  // Single pass: collect only this user's transactions
  const userTransactions: Transaction[] = [];
  for (const t of transactions) {
    if (t.userId === userId) {
      userTransactions.push(t);
    }
  }

  // Sort once by date
  userTransactions.sort((a, b) => a.date.localeCompare(b.date));

  // Single accumulation pass
  const entries: RunningBalanceEntry[] = [];
  let balance = 0;
  for (const t of userTransactions) {
    balance += t.amount;
    entries.push({
      transactionId: t.id,
      amount: t.amount,
      balance: Math.round(balance * 100) / 100,
      date: t.date,
    });
  }

  return entries;
}

/**
 * Returns the top N spenders.
 *
 * Optimized: single O(n) pass with a Map to accumulate per-user totals and
 * counts, then O(u log u) native sort instead of O(u^2) bubble sort.
 */
export function topSpenders(
  transactions: Transaction[],
  n: number
): SpenderSummary[] {
  const map = new Map<string, { total: number; count: number }>();

  for (const t of transactions) {
    const entry = map.get(t.userId);
    if (entry) {
      entry.total += t.amount;
      entry.count += 1;
    } else {
      map.set(t.userId, { total: t.amount, count: 1 });
    }
  }

  const summaries: SpenderSummary[] = [];
  for (const [userId, { total, count }] of map) {
    summaries.push({
      userId,
      totalSpent: Math.round(total * 100) / 100,
      transactionCount: count,
    });
  }

  summaries.sort((a, b) => b.totalSpent - a.totalSpent);

  return summaries.slice(0, n);
}

/**
 * Searches transactions by description text.
 *
 * Optimized: compile the RegExp once outside the loop; use a Set for O(1)
 * duplicate-id tracking instead of a linear scan.
 */
export function searchTransactions(
  transactions: Transaction[],
  query: string
): Transaction[] {
  const pattern = new RegExp(query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"), "i");
  const seen = new Set<string>();
  const results: Transaction[] = [];

  for (const transaction of transactions) {
    if (pattern.test(transaction.description) && !seen.has(transaction.id)) {
      seen.add(transaction.id);
      results.push(transaction);
    }
  }

  return results;
}

/**
 * Runs the full processing pipeline.
 */
export function processAll(
  transactions: Transaction[],
  topN: number = 10
): PipelineResult {
  const categoryGroups = groupByCategory(transactions);
  const duplicates = findDuplicates(transactions);
  const topSpendersList = topSpenders(transactions, topN);

  return {
    categoryGroups,
    duplicates,
    topSpenders: topSpendersList,
  };
}

